sp_widget.client_script:
function ITSMIncidentCreator($scope, spUtil) {
    var c = this;
    c.isSubmitting = false;
    c.successMessage = null;
    c.errorMessage = null;
    c.isLoading = false;

    c.onCategoryChange = function() {
        c.data.subcategories = [];
        c.data.subcategory = '';
        if (c.data.category) {
            c.server.get({action: 'getSubcategories', category: c.data.category})
                .then(function(response) {
                    if (response.data && response.data.subcategories) {
                        c.data.subcategories = response.data.subcategories;
                    }
                });
        }
    };

    c.submitIncident = function() {
        if (!c.data.short_description || !c.data.category || !c.data.subcategory || !c.data.description) {
            c.errorMessage = 'Please fill in all required fields.';
            return;
        }
        c.isSubmitting = true;
        c.errorMessage = null;
        c.server.get({
            action: 'createIncident',
            short_description: c.data.short_description,
            category: c.data.category,
            subcategory: c.data.subcategory,
            description: c.data.description,
            urgency: c.data.urgency
        }).then(function(response) {
            c.isSubmitting = false;
            if (response.data && response.data.success) {
                c.successMessage = response.data.message;
                spUtil.publish('incident.created', {incidentNumber: response.data.number});
            } else {
                c.errorMessage = response.data.error || 'Failed to create incident. Please try again.';
            }
        }, function(error) {
            c.isSubmitting = false;
            c.errorMessage = 'An unexpected error occurred. Please try again.';
        });
    };

    c.resetForm = function() {
        c.data.short_description = '';
        c.data.category = '';
        c.data.subcategory = '';
        c.data.subcategories = [];
        c.data.description = '';
        c.data.urgency = '2';
        c.successMessage = null;
        c.errorMessage = null;
        c.isSubmitting = false;
        if ($scope.incidentForm) {
            $scope.incidentForm.$setPristine();
            $scope.incidentForm.$setUntouched();
        }
    };
}

sp_widget.css:
#itsm-incident-creator {
  max-width: 800px;
  margin: 0 auto;
  padding: 20px;
  font-family: 'Segoe UI', 'Helvetica Neue', Arial, sans-serif;
}
.itsm-header {
  text-align: center;
  padding: 30px 20px;
  background: linear-gradient(135deg, #2c3e50 0%, #3498db 100%);
  color: white;
  border-radius: 8px;
  margin-bottom: 25px;
  box-shadow: 0 4px 15px rgba(0, 0, 0, 0.1);
}
.itsm-header h1 { margin: 0 0 10px 0; font-size: 28px; font-weight: 300; }
.itsm-header h1 .glyphicon { margin-right: 10px; font-size: 24px; }
.itsm-header p { margin: 0; font-size: 14px; opacity: 0.9; }
.itsm-form .panel { border: 1px solid #e0e0e0; border-radius: 6px; box-shadow: 0 2px 6px rgba(0,0,0,0.05); margin-bottom: 20px; }
.itsm-form .panel-heading { background: #f8f9fa; border-bottom: 1px solid #e0e0e0; padding: 12px 15px; }
.itsm-form .panel-title { font-size: 15px; font-weight: 600; color: #333; }
.itsm-form .panel-title .glyphicon { margin-right: 8px; color: #3498db; }
.itsm-form .panel-body { padding: 20px; }
.itsm-form .form-group { margin-bottom: 18px; }
.itsm-form label { font-weight: 600; color: #333; font-size: 13px; margin-bottom: 6px; }
.itsm-form .form-control { border: 1px solid #ccc; border-radius: 4px; padding: 10px 12px; font-size: 14px; transition: border-color 0.3s ease, box-shadow 0.3s ease; }
.itsm-form .form-control:focus { border-color: #3498db; box-shadow: 0 0 0 2px rgba(52,152,219,0.2); }
.itsm-form .form-control[readonly] { background: #f8f9fa; cursor: not-allowed; }
.itsm-form textarea.form-control { resize: vertical; min-height: 120px; }
.itsm-form select.form-control { cursor: pointer; }
.itsm-form .text-muted { font-size: 12px; color: #6c757d; margin-top: 4px; display: block; }
.itsm-form .text-danger { color: #dc3545; }
.itsm-form .form-control.ng-touched.ng-invalid { border-color: #dc3545; }
.itsm-form .form-control.ng-touched.ng-invalid:focus { box-shadow: 0 0 0 2px rgba(220,53,69,0.2); }
.itsm-actions { text-align: center; padding: 15px 0; }
.itsm-actions .btn { margin: 5px 10px; min-width: 180px; border-radius: 4px; font-size: 15px; padding: 12px 24px; transition: all 0.3s ease; }
.itsm-actions .btn-primary { background: #3498db; border-color: #3498db; }
.itsm-actions .btn-primary:hover:not(:disabled) { background: #2980b9; border-color: #2980b9; transform: translateY(-1px); box-shadow: 0 4px 10px rgba(52,152,219,0.3); }
.itsm-actions .btn-primary:disabled { opacity: 0.6; cursor: not-allowed; }
.itsm-actions .btn-default { background: #f8f9fa; border-color: #ccc; }
.itsm-actions .btn-default:hover { background: #e9ecef; border-color: #b0b0b0; }
.itsm-success .alert-success { text-align: center; padding: 30px; margin: 20px 0; border: 1px solid #c3e6cb; background: #d4edda; border-radius: 8px; }
.itsm-success .alert-success .glyphicon { font-size: 36px; display: block; margin-bottom: 15px; color: #28a745; }
.itsm-success .alert-success strong { display: block; font-size: 20px; margin-bottom: 10px; color: #155724; }
.itsm-success .alert-success p { font-size: 14px; color: #155724; margin-bottom: 20px; white-space: pre-line; }
.itsm-success .btn-primary { background: #28a745; border-color: #28a745; }
.itsm-success .btn-primary:hover { background: #218838; border-color: #1e7e34; }
.itsm-error .alert-danger { border: 1px solid #f5c6cb; background: #f8d7da; border-radius: 6px; padding: 15px; margin: 10px 0; }
.itsm-loading .spinner { width: 40px; height: 40px; border: 3px solid #f0f0f0; border-top: 3px solid #3498db; border-radius: 50%; animation: spin 1s linear infinite; display: inline-block; }
@keyframes spin { 0% { transform: rotate(0deg); } 100% { transform: rotate(360deg); } }
@media (max-width: 768px) {
  #itsm-incident-creator { padding: 10px; }
  .itsm-header { padding: 20px 15px; }
  .itsm-header h1 { font-size: 22px; }
  .itsm-actions .btn { width: 100%; margin: 5px 0; }
}
